#include <iostream>
#include <algorithm>
#include <vector>

using namespace std;

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(nullptr);

    vector<int> a(4);
    for (int i = 0; i < 4; ++i) {
        cin >> a[i];
    }

    // Sort to make checking easier
    sort(a.begin(), a.end());

    bool triangle = false; // positive area
    bool segment = false;  // zero area (degenerate)

    // Try all combinations of 3 sticks out of 4
    for (int i = 0; i < 4; ++i) {
        for (int j = i + 1; j < 4; ++j) {
            for (int k = j + 1; k < 4; ++k) {
                int x = a[i], y = a[j], z = a[k];
                // For a non-degenerate triangle, the sum of the two smallest
                // must be strictly greater than the largest.
                if (x + y > z) {
                    triangle = true;
                } else if (x + y == z) {
                    segment = true;
                }
            }
        }
    }

    if (triangle) {
        cout << "TRIANGLE\n";
    } else if (segment) {
        cout << "SEGMENT\n";
    } else {
        cout << "IMPOSSIBLE\n";
    }

    return 0;
}
